CREATE SEQUENCE xeus.bigdata_analy_weight${value}_mgr_seq_seq;

CREATE TABLE xeus.bigdata_analy_weight${value}
(
    mgr_seq bigint NOT NULL DEFAULT nextval('xeus.bigdata_analy_weight${value}_mgr_seq_seq'::regclass),
    analy_mgr_seq numeric(32,0) NOT NULL,
    layer_id character varying(100) COLLATE pg_catalog."default" NOT NULL,
    item_nm character varying(100) COLLATE pg_catalog."default",
    min_val numeric(8,0),
    max_val numeric(8,0),
    weight_val numeric(8,0),
    impact_m numeric(8,0),
    CONSTRAINT bigdata_analy_weight${value}_pk PRIMARY KEY (mgr_seq)
);

CREATE INDEX bigdata_analy_weight${value}_mgr_seq_idx ON xeus.bigdata_analy_weight${value} USING btree (analy_mgr_seq, layer_id COLLATE pg_catalog."default") TABLESPACE pg_default;

